import { useState, useRef, useEffect } from "react"
import {
  BRIDE_FULLNAME,
  GROOM_FULLNAME,
  LOCATION,
  WEDDING_DATE,
} from "../../const"
import coverImage from "../../image/cover.png"
import myMusic from "../../image/jxxn.mp3"
import { ReactComponent as AudioOnIcon } from "../../image/audio-on.svg"
import { ReactComponent as AudioOffIcon } from "../../image/audio-off.svg"
import { LazyDiv } from "../lazyDiv"
import { Button } from "../button"

const DAY_OF_WEEK = [
  "Sunday",
  "Monday",
  "Tuesday",
  "Wednesday",
  "Thursday",
  "Friday",
  "Saturday",
]

export const Cover = () => {

  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef(new Audio(myMusic));

  const togglePlay = () => {
    setIsPlaying(!isPlaying);
  };
  
  useEffect(() => {
    const audio = audioRef.current;
    isPlaying ? audio.play() : audio.pause();
    return () => {
      audio.pause();
      audio.currentTime = 0; // Ensure music starts from the beginning next time
    };
  }, [isPlaying]);

  return (
    <LazyDiv className="card cover">
      <div className='music'>
        {isPlaying ? (
            <Button className='music-button'><AudioOffIcon className='cover__music-btn' onClick={togglePlay} aria-label="Stop Music"/></Button>
          ) : (
            <Button className='music-button'><AudioOnIcon className='cover__music-btn' onClick={togglePlay} aria-label="Play Music"/></Button>
          )}
      </div>
        <h1 className="english">
          2025 / 12 / 21
          <br />
          {DAY_OF_WEEK[WEDDING_DATE.day()]}
        </h1>
      <div className="image-wrapper">
        <img src={coverImage} alt="sample" />
      </div>
      <div className="subtitle">The wedding of</div>
      <div className="names">
        {GROOM_FULLNAME} 🤍 {BRIDE_FULLNAME}
      </div>
      <div className="info">
        {WEDDING_DATE.format("YYYY년 MMMM D일 dddd A h시")}
      </div>
      <div className="info">{LOCATION}, 41층 파노라마홀</div>
    </LazyDiv>
  )
}
